function sortAgents(list) {
    return list.sort((a, b) => {
        if (a.role === 'coordinator') return -1;
        if (b.role === 'coordinator') return 1;
        return a.name.localeCompare(b.name);
    });
}

async function init() {
    const res = await fetch(`${API_BASE}/api/agents`);
    const agentList = sortAgents(await res.json());

    const dashboard = document.getElementById('dashboard');
    const count = agentList.length;
    document.getElementById('agent-count').textContent = `${count} agent${count !== 1 ? 's' : ''}`;

    // Choose grid columns based on agent count
    if (count <= 1) dashboard.className = 'dashboard cols-1';
    else if (count <= 2) dashboard.className = 'dashboard cols-2';
    else if (count <= 3) dashboard.className = 'dashboard cols-3';
    else dashboard.className = 'dashboard cols-4';

    for (const agent of agentList) {
        const panel = createAgentPanel(agent);
        dashboard.appendChild(panel);

        const { term, fitAddon } = initTerminal(agent.id);
        agents.set(agent.id, { term, fitAddon, panel, evtSource: null });

        connectSSE(agent.id);
        setupControls(agent.id);
    }

    // Fetch per-agent saga step for badges
    pollAgentSagas(agentList.map(a => a.id));

    // Handle resize
    const fitAll = () => agents.forEach((a, id) => {
        a.fitAddon.fit();
        syncPtySize(id, a.term);
    });
    window.addEventListener('resize', fitAll);
    new ResizeObserver(fitAll).observe(dashboard);

    // Poll states
    setInterval(pollStates, 2000);
}

