537	/// Create a new agent session.
538	async fn create_agent(
539	    State(state): State<AppState>,
540	    Json(body): Json<CreateAgentBody>,
541	) -> Result<StatusCode, (StatusCode, String)> {
542	    let id = body.id.clone();
543	
544	    // Check if agent already exists.
545	    {
546	        let configs = state.agent_configs.lock().await;
547	        if configs.contains_key(&id) {
548	            return Err((StatusCode::CONFLICT, format!("Agent '{id}' already exists")));
549	        }
550	    }
551	
552	    let role = parse_role(&body.role);
553	    let repo_path = if std::path::Path::new(&body.repo_path).is_absolute() {
554	        PathBuf::from(&body.repo_path)
555	    } else {
556	        state.base_dir.join(&body.repo_path)
557	    };
558	
559	    let config = AgentConfig {
560	        id: AgentId(id.clone()),
561	        name: body.name,
562	        repo_path: repo_path.clone(),
563	        role,
564	        setup_commands: body.setup_commands,
565	        launch_command: body.launch_command,
566	    };
567	
568	    // Spawn the agent session.
569	    {
570	        let mut mgr = state.manager.lock().await;
571	        mgr.spawn_agent(config.clone()).map_err(|e| {
572	            (
573	                StatusCode::INTERNAL_SERVER_ERROR,
574	                format!("Failed to spawn agent: {e}"),
575	            )
576	        })?;
577	    }
578	
579	    // Store config and repo path.
580	    {
581	        let mut configs = state.agent_configs.lock().await;
582	        configs.insert(id.clone(), config);
583	    }
584	    {
585	        let mut repo_paths = state.agent_repo_paths.lock().await;
586	        repo_paths.insert(id.clone(), repo_path);
587	    }
588	
589	    tracing::info!("Created agent: {id}");
590	    Ok(StatusCode::CREATED)
591	}
592	
593	/// Delete (destroy) an agent session.
594	async fn delete_agent(
595	    Path(id): Path<String>,
596	    State(state): State<AppState>,
597	) -> Result<StatusCode, StatusCode> {
598	    let agent_id = AgentId(id.clone());
599	
600	    // Remove session.
601	    let old_session = {
602	        let mut mgr = state.manager.lock().await;
603	        mgr.remove_agent(&agent_id)
604	            .map_err(|_| StatusCode::NOT_FOUND)?
605	    };
606	
607	    // Shutdown gracefully.
608	    let mut session = old_session;
609	    let _ = session.shutdown().await;
610	
