    let reader_handle = spawn_reader_task(reader, output_tx.clone());

    // Optionally start transcript logging (output + input).
    let input_log_path = if let Some(ref dir) = log_dir {
        let agent_dir = dir.join(&config.id.0);
        let _ = std::fs::create_dir_all(&agent_dir);
        Some(agent_dir.join("inputs.jsonl"))
    } else {
        None
    };
    let writer_handle = spawn_writer_task(writer, input_rx, input_log_path);

    let transcript_handle = if let Some(dir) = log_dir {
        let agent_dir = dir.join(&config.id.0);
        let tw = TranscriptWriter::new(&agent_dir)?;
        let rx = output_tx.subscribe();
        Some(tw.spawn(rx))
    } else {
        None
    };

    // Start the state tracker.
    let state_tracker_rx = output_tx.subscribe();
    let state_tracker_handle = spawn_state_tracker(state_tracker_rx, state.clone());

    // Inject setup commands.
    let setup_tx = input_tx.clone();
    let setup_commands = config.setup_commands.clone();
    let launch = config.launch_command.clone();
    let state_clone = state.clone();
    tokio::spawn(async move {
        // Set a known prompt for the outer shell.
        let _ = setup_tx
            .send(InputEvent::CoordinatorCommand {
                command: r#"export PS1="__ATN_READY__> ""#.to_string(),
            })
            .await;

        for cmd in &setup_commands {
            let _ = setup_tx
                .send(InputEvent::CoordinatorCommand {
                    command: cmd.clone(),
                })
                .await;
        }

        if !launch.is_empty() {
            let _ = setup_tx
                .send(InputEvent::CoordinatorCommand { command: launch })
                .await;
        }

        let mut s = state_clone.write().await;
        *s = AgentState::Running;
    });

    Ok(Self {
        agent_id: config.id.clone(),
        agent_name: config.name.clone(),
        agent_role: format!("{:?}", config.role).to_lowercase(),
