        input_tx,
        output_tx,
        state,
        _master: pair.master,
        _reader_handle: reader_handle,
        _writer_handle: writer_handle,
        _transcript_handle: transcript_handle,
        _state_tracker_handle: state_tracker_handle,
    })
}

