        .saga-none { color: #666; font-size: 14px; padding: 40px; text-align: center; }

        /* Restart / Stop / Delete buttons */
        .btn-restart { background: #1e3a5f; color: #60a5fa; font-size: 11px; padding: 6px 8px; }
        .btn-restart:hover { background: #264f78; }
        .btn-stop { background: #78350f; color: #fbbf24; font-size: 11px; padding: 6px 8px; }
        .btn-stop:hover { background: #92400e; }
        .btn-delete { background: #7f1d1d; color: #fca5a5; font-size: 11px; padding: 6px 8px; }
        .btn-delete:hover { background: #991b1b; }
        .btn-edit-cfg { background: transparent; color: #888; font-size: 11px; padding: 6px 8px; border: 1px solid #0f3460; }
        .btn-edit-cfg:hover { background: #0f3460; color: #c9d1d9; }
        .btn-save-cfg { background: #4ecca3; color: #1a1a2e; font-size: 12px; padding: 4px 12px; border: none; border-radius: 4px; cursor: pointer; }
        .btn-save-cfg:hover { background: #3db892; }

        /* New agent form */
        .new-agent-bar { padding: 8px; border-bottom: 1px solid #0f3460; background: #16213e; flex-shrink: 0; display: none; }
        .new-agent-bar.visible { display: block; }
        .new-agent-form { display: flex; gap: 6px; align-items: center; flex-wrap: wrap; }
        .new-agent-form input, .new-agent-form select { padding: 5px 8px; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-size: 12px; outline: none; }
        .new-agent-form input:focus { border-color: #e94560; }
        .new-agent-form .field-id { width: 100px; }
        .new-agent-form .field-name { width: 140px; }
        .new-agent-form .field-path { width: 200px; }
        .new-agent-form .field-launch { width: 120px; }
        .new-agent-form button { padding: 5px 14px; border: none; border-radius: 4px; cursor: pointer; font-size: 12px; font-weight: 500; }
        .new-agent-form .btn-create { background: #4ecca3; color: #1a1a2e; }
        .new-agent-form .btn-create:hover { background: #3db892; }
        .new-agent-form .btn-cancel { background: transparent; color: #888; border: 1px solid #0f3460; }

        /* Agent config editor overlay */
        .agent-config-editor { display: none; padding: 8px; border-top: 1px solid #0f3460; background: #0d1117; font-size: 12px; }
        .agent-config-editor.visible { display: block; }
        .agent-config-editor label { display: block; color: #888; margin-top: 4px; font-size: 11px; }
        .agent-config-editor input, .agent-config-editor select { width: 100%; padding: 4px 6px; background: #1a1a2e; border: 1px solid #0f3460; border-radius: 3px; color: #e0e0e0; font-size: 12px; outline: none; margin-top: 2px; }
        .agent-config-editor .cfg-btns { display: flex; gap: 6px; margin-top: 6px; }
        .agent-config-editor .cfg-btns button { padding: 4px 10px; border: none; border-radius: 4px; cursor: pointer; font-size: 11px; }

        /* Dependency graph */
        .graph-container { flex: 1; display: flex; flex-direction: column; min-height: 0; overflow: hidden; padding: 8px; }
        .graph-toolbar { display: flex; align-items: center; gap: 8px; padding: 8px; flex-shrink: 0; }
        .graph-toolbar h2 { font-size: 16px; color: #c9d1d9; flex: 1; }
        .graph-toolbar button { padding: 4px 10px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #c9d1d9; cursor: pointer; font-size: 12px; }
        .graph-toolbar button:hover { background: #0f3460; }
        .graph-canvas { flex: 1; overflow: auto; display: flex; align-items: center; justify-content: center; }
        .graph-svg { max-width: 100%; max-height: 100%; }
        .graph-node { cursor: pointer; }
        .graph-node rect { stroke-width: 2; rx: 8; ry: 8; }
        .graph-node text { fill: #c9d1d9; font-size: 13px; font-family: system-ui, sans-serif; }
        .graph-edge { stroke: #e94560; stroke-width: 2; fill: none; marker-end: url(#arrowhead); }
    </style>
