function toggleNewAgent() {
    const bar = document.getElementById('new-agent-bar');
    bar.classList.toggle('visible');
    if (bar.classList.contains('visible')) {
        updateTransportFields();
        updateCommandPreview();
    }
}

function updateTransportFields() {
    const transport = document.getElementById('new-transport').value;
    const remote = transport !== 'local';
    document.getElementById('new-user').disabled = !remote;
    document.getElementById('new-host').disabled = !remote;
    if (!remote) {
        document.getElementById('new-user').value = '';
        document.getElementById('new-host').value = '';
    }
    updateCommandPreview();
}

function readSpawnSpec() {
    const cliSel = document.getElementById('new-agent-cli');
    const customEl = document.getElementById('new-agent-custom');
    customEl.style.display = cliSel.value === '' ? 'inline-block' : 'none';
    const agentName = cliSel.value === '' ? customEl.value.trim() : cliSel.value;
    const name = document.getElementById('new-name').value.trim();
    const role = document.getElementById('new-role').value;
    const transport = document.getElementById('new-transport').value;
    const host = document.getElementById('new-host').value.trim();
    const user = document.getElementById('new-user').value.trim();
    const workingDir = document.getElementById('new-dir').value.trim();
    const project = document.getElementById('new-project').value.trim();
    const agentArgs = document.getElementById('new-agent-args').value.trim();
    return {
        name, role, transport,
        host: host || null,
        user: user || null,
        working_dir: workingDir,
        project: project || null,
        agent: agentName,
        agent_args: agentArgs || null,
    };
}

function validateSpec(s) {
    const missing = [];
    if (!s.name) missing.push('name');
    if (!s.working_dir) missing.push('working_dir');
    if (!s.agent) missing.push('agent');
    if (s.transport !== 'local') {
        if (!s.host) missing.push('host');
        if (!s.user) missing.push('user');
    }
    return missing;
}

function previewCommand(s) {
    const tail = s.agent_args ? `${s.agent} ${s.agent_args}` : s.agent;
    const inner = `cd ${s.working_dir || '<dir>'} && ${tail || '<agent>'}`;
    if (s.transport === 'local') return inner;
    const bin = s.transport; // mosh | ssh
    const user = s.user || '<user>';
    const host = s.host || '<host>';
    const sess = `atn-${s.name || '<name>'}`;
    return `${bin} ${user}@${host} -- tmux new-session -A -s ${sess} '${inner}'`;
}

function updateCommandPreview() {
    const spec = readSpawnSpec();
    document.getElementById('new-agent-preview').textContent = previewCommand(spec);
    const missing = validateSpec(spec);
    const err = document.getElementById('new-agent-err');
    err.textContent = missing.length ? `missing: ${missing.join(', ')}` : '';
}

['new-name','new-role','new-transport','new-host','new-user','new-dir',
 'new-project','new-agent-cli','new-agent-custom','new-agent-args'].forEach(id => {
    document.addEventListener('DOMContentLoaded', () => {
        const el = document.getElementById(id);
        if (el) el.addEventListener('input', updateCommandPreview);
        if (el && el.tagName === 'SELECT') el.addEventListener('change', updateCommandPreview);
    });
});

async function createAgent() {
    const spec = readSpawnSpec();
    const missing = validateSpec(spec);
    if (missing.length) {
        document.getElementById('new-agent-err').textContent =
            `missing: ${missing.join(', ')}`;
        return;
    }
    try {
        const res = await fetch(`${API_BASE}/api/agents`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(spec),
        });
        if (res.status === 201) {
            const info = await res.json();
            // Clear form.
            ['new-name','new-host','new-user','new-dir','new-project','new-agent-args','new-agent-custom']
                .forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
            document.getElementById('new-agent-err').textContent = '';
            document.getElementById('new-agent-preview').textContent = '';
            document.getElementById('new-agent-bar').classList.remove('visible');
            // Drop any existing empty-state card.
            document.querySelectorAll('.empty-state').forEach(n => n.remove());
            addAgentPanel({
                id: info.id, name: info.name, role: info.role,
                state: { state: 'starting' },
            });
        } else {
            const body = await res.json().catch(() => ({error:'unknown'}));
            document.getElementById('new-agent-err').textContent =
                `${body.error}${body.missing ? ': ' + body.missing.join(', ') : ''}`;
        }
    } catch (e) {
        document.getElementById('new-agent-err').textContent = `network error: ${e}`;
    }
}

