    const tail = s.agent_args ? `${s.agent} ${s.agent_args}` : s.agent;
    const inner = `cd ${s.working_dir || '<dir>'} && ${tail || '<agent>'}`;
    if (s.transport === 'local') return inner;
    const bin = s.transport; // mosh | ssh
    const user = s.user || '<user>';
    const host = s.host || '<host>';
    const sess = `atn-${s.name || '<name>'}`;
    return `${bin} ${user}@${host} -- tmux new-session -A -s ${sess} '${inner}'`;
}

function updateCommandPreview() {
    const spec = readSpawnSpec();
    document.getElementById('new-agent-preview').textContent = previewCommand(spec);
    const missing = validateSpec(spec);
    const err = document.getElementById('new-agent-err');
    err.textContent = missing.length ? `missing: ${missing.join(', ')}` : '';
}

['new-name','new-role','new-transport','new-host','new-user','new-dir',
 'new-project','new-agent-cli','new-agent-custom','new-agent-args'].forEach(id => {
    document.addEventListener('DOMContentLoaded', () => {
        const el = document.getElementById(id);
        if (el) el.addEventListener('input', updateCommandPreview);
        if (el && el.tagName === 'SELECT') el.addEventListener('change', updateCommandPreview);
    });
