async function createAgent() {
    const spec = readSpawnSpec();
    const missing = validateSpec(spec);
    if (missing.length) {
        document.getElementById('new-agent-err').textContent =
            `missing: ${missing.join(', ')}`;
        return;
    }
    try {
        const res = await fetch(`${API_BASE}/api/agents`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(spec),
        });
        if (res.status === 201) {
            const info = await res.json();
            // Clear form.
            ['new-name','new-host','new-user','new-dir','new-project','new-agent-args','new-agent-custom']
                .forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
            document.getElementById('new-agent-err').textContent = '';
            document.getElementById('new-agent-preview').textContent = '';
            document.getElementById('new-agent-bar').classList.remove('visible');
            // Drop any existing empty-state card.
            document.querySelectorAll('.empty-state').forEach(n => n.remove());
            addAgentPanel({
                id: info.id, name: info.name, role: info.role,
                state: { state: 'starting' },
            });
        } else {
            const body = await res.json().catch(() => ({error:'unknown'}));
            document.getElementById('new-agent-err').textContent =
                `${body.error}${body.missing ? ': ' + body.missing.join(', ') : ''}`;
        }
    } catch (e) {
        document.getElementById('new-agent-err').textContent = `network error: ${e}`;
    }
}

