use serde::{Deserialize, Serialize};
use yew::prelude::*;

use crate::wiki::WikiBrowser;

#[derive(Clone, Debug, Deserialize, PartialEq)]
struct AgentInfo {
    id: String,
    name: String,
    role: String,
}

#[derive(Clone, PartialEq)]
enum ViewMode {
    Agents,
    Wiki,
}

#[derive(Clone, Debug, Serialize, PartialEq)]
struct SpawnSpecForm {
    name: String,
    role: String,
    transport: String,
    host: Option<String>,
    user: Option<String>,
    working_dir: String,
    project: Option<String>,
    agent: String,
    agent_args: Option<String>,
}

impl Default for SpawnSpecForm {
    fn default() -> Self {
        Self {
            name: String::new(),
            role: "worker".to_string(),
            transport: "local".to_string(),
            host: None,
            user: None,
            working_dir: String::new(),
            project: None,
            agent: "claude".to_string(),
            agent_args: None,
        }
    }
}

impl SpawnSpecForm {
    fn is_remote(&self) -> bool {
        self.transport != "local"
    }

    fn missing_fields(&self) -> Vec<&'static str> {
        let mut m = Vec::new();
        if self.name.trim().is_empty() {
            m.push("name");
        }
        if self.working_dir.trim().is_empty() {
            m.push("working_dir");
        }
        if self.agent.trim().is_empty() {
            m.push("agent");
        }
        if self.is_remote() {
            if self.host.as_deref().map(str::trim).unwrap_or("").is_empty() {
                m.push("host");
            }
            if self.user.as_deref().map(str::trim).unwrap_or("").is_empty() {
                m.push("user");
            }
        }
        m
    }

    fn preview(&self) -> String {
        let tail = match self.agent_args.as_deref() {
            Some(a) if !a.trim().is_empty() => format!("{} {}", self.agent, a.trim()),
            _ => self.agent.clone(),
        };
        let dir = if self.working_dir.is_empty() {
            "<dir>".to_string()
        } else {
            self.working_dir.clone()
        };
        let agent = if tail.is_empty() {
            "<agent>".to_string()
        } else {
            tail
        };
        let inner = format!("cd {dir} && {agent}");
        if self.transport == "local" {
            return inner;
        }
        let user = self.user.as_deref().unwrap_or("<user>");
        let host = self.host.as_deref().unwrap_or("<host>");
        let name = if self.name.is_empty() {
            "<name>"
        } else {
            self.name.as_str()
        };
        format!(
            "{bin} {user}@{host} -- tmux new-session -A -s atn-{name} '{inner}'",
            bin = self.transport,
        )
    }
}

