    FeatureRequest,
    BugFixRequest,
    CompletionNotice,
    BlockedNotice,
    NeedsInfo,
    VerificationRequest,
}

/// Priority level for a push event.
#[derive(Clone, Debug, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "lowercase")]
