        mgr.spawn_agent(config).map_err(|e| {
            tracing::error!("Failed to reconnect agent '{id}': {e}");
            StatusCode::INTERNAL_SERVER_ERROR
        })?;
    }

    tracing::info!("Reconnected agent: {id}");
    Ok(StatusCode::OK)
}

